    "ef517f20-03e8-47f6-a111-61398bbf5c17": {"id":"ef517f20-03e8-47f6-a111-61398bbf5c17","project_id":24447,"key":86681884,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-12-14T00:12:04.965Z","updated_at":"2023-12-14T00:12:04.965Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003cdiv class=\"chameleon-text-align-center\" data-type=\"textAlignCenter\"\u003e\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003e\u003cspan class=\"css-wuezvu-rules\" style=\"color:#fff\" data-type=\"color\"\u003eTime for the short quiz \u003c/span\u003e\u003c/p\u003e\u003c/h5\u003e\u003c/div\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cdiv class=\"chameleon-text-align-center\" data-type=\"textAlignCenter\"\u003e\u003cp data-type=\"paragraph\"\u003e\u003cspan class=\"css-wuezvu-rules\" style=\"color:#fff\" data-type=\"color\"\u003eYou will need to get all questions right, if you don\u0026#x27;t receive a passing mark, come back and attempt the quiz again. \u003c/span\u003e\u003c/p\u003e\u003c/div\u003e"},"type":"Text"}, 
    "f6ed0258-aee5-4e00-8256-0820833ec6ef": {"id":"f6ed0258-aee5-4e00-8256-0820833ec6ef","project_id":24447,"key":83687967,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-29T19:58:20.232Z","updated_at":"2023-11-29T19:58:20.232Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003eAsbestos in New Zealand \u003c/p\u003e\u003c/h5\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eNew Zealand is one of 69 countries that has banned the use of asbestos. \u003c/p\u003e"},"type":"Text"}, 
    "9f815cf5-1449-47be-af2b-dccc8b8dcb48": {"id":"9f815cf5-1449-47be-af2b-dccc8b8dcb48","project_id":24447,"key":83687949,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-29T19:57:29.113Z","updated_at":"2023-11-29T19:57:29.113Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003eWhat we\u0026#x27;ll cover\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003c/h5\u003e\u003cul class=\"chameleon-ul\" data-type=\"bulleted-list\"\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eWhat is asbestos\u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eWhy is it dangerous to my health\u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eTypes of asbestos\u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eWho is at risk \u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eWhere is likely places for asbestos to be found \u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eOverview of our controls and processes\u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eQuiz\u003c/li\u003e\u003c/ul\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eWe also have developed a role specific asbestos related module. Be sure to check that out. \u003c/p\u003e"},"type":"Text"}, 
    "305013ad-f254-4d2a-afbd-adb3f05eb1ad": {"id":"305013ad-f254-4d2a-afbd-adb3f05eb1ad","project_id":24447,"key":83687948,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-29T19:57:28.678Z","updated_at":"2023-11-29T19:57:28.678Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003eIntroduction \u003c/p\u003e\u003c/h5\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eAt HRV we care about our team\u0026#x27;s safety and wellbeing. This module is designed to educate our team on the subject of asbestos. What to look out for, where you might be exposed to asbestos and the controls to protect you. \u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eAlso, our customers are front of mind and reassuring them that HRV is committed to protecting both its team members and occupants of any property it is engaged to work in.\u003c/p\u003e"},"type":"Text"}, 
    "04b66287-9b9a-4da3-b040-8adab0dfa198": {"id":"04b66287-9b9a-4da3-b040-8adab0dfa198","project_id":24447,"key":82770188,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-23T20:56:33.650Z","updated_at":"2023-11-23T20:56:33.650Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eTo successfully complete this module you need to achieve a 100% mark. The module will continue to stay on your learning profile until the required mark is achieved. \u003c/p\u003e"},"type":"Text"}, 
