    "e2a6a7cd-c63f-4d65-9f73-90ad008d1215": {"id":"e2a6a7cd-c63f-4d65-9f73-90ad008d1215","project_id":24447,"key":81437434,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-16T20:37:31.781Z","updated_at":"2023-11-16T20:37:31.781Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003eConclusion \u003c/p\u003e\u003c/h5\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eAsbestos is a complex subject. Stay alert, always take the time to follow procedures, and support your workmates.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eIf you are ever unsure if it is safe to work - stop - discuss it with your team leader. \u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eNothing is more important than your health and safety.\u003c/p\u003e"},"type":"Text"}, 
    "b0d44c07-8ea1-46ae-9a72-7ba483442eb3": {"id":"b0d44c07-8ea1-46ae-9a72-7ba483442eb3","project_id":24447,"key":81436593,"version":null,"meta":{},"children":[{"id":"ee952301-d4a3-482d-a9c3-f62bcf24a46d","type":"Ref"},{"id":"49c8b3a4-9cf0-49a2-a872-85debc3390f2","type":"Ref"}],"deleted_at":null,"created_at":"2023-11-16T20:16:32.131Z","updated_at":"2023-11-16T20:16:32.131Z","props":{"headerStyle":"standard"},"type":"Header"}, 
    "2b056df7-e5b7-4038-9328-1b323fb4e5b0": {"id":"2b056df7-e5b7-4038-9328-1b323fb4e5b0","project_id":24447,"key":81436273,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-16T20:13:25.008Z","updated_at":"2023-11-16T20:13:25.008Z","props":{"enableTextToSpeechBtn":true,"content":"\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003eThe Law and Asbestos \u003c/p\u003e\u003c/h5\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eThere are legal requirements when working with Asbestos. Some of these requirements are presented in:\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cul class=\"chameleon-ul\" data-type=\"bulleted-list\"\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eHealth \u0026amp; Safety At Work Act 2015\u003c/li\u003e\u003c/ul\u003e\u003cul class=\"chameleon-ul\" data-type=\"bulleted-list\"\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eHealth \u0026amp; Safety At Work (Asbestos) Regulations 2016\u003c/li\u003e\u003c/ul\u003e\u003cul class=\"chameleon-ul\" data-type=\"bulleted-list\"\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eAsbestos Approved Code of Practice 2016\u003c/li\u003e\u003c/ul\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eClick through the carousel to see the highlight reel.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eIf your work includes potential exposure to asbestos, you must:\u003c/p\u003e"},"type":"Text"}, 
    "f9057841-7ad7-455a-bda8-7dcf8480a152": {"id":"f9057841-7ad7-455a-bda8-7dcf8480a152","project_id":24447,"key":81436272,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-16T20:13:23.746Z","updated_at":"2023-11-16T20:13:23.746Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003eLet\u0026#x27;s recap\u003c/p\u003e\u003c/h5\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eHRV \u003cstrong data-type=\"bold\"\u003edoes not disturb\u003c/strong\u003e or work with \u003cstrong data-type=\"bold\"\u003efriable asbestos\u003c/strong\u003e. We are\u003cstrong data-type=\"bold\"\u003e permitted\u003c/strong\u003e to carry out asbestos-related work on \u003cstrong data-type=\"bold\"\u003enon-friable\u003c/strong\u003e ACM if the area of work is \u003cstrong data-type=\"bold\"\u003eless\u003c/strong\u003e than 10 square metres. \u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eOnly \u003cstrong data-type=\"bold\"\u003etrained\u003c/strong\u003e HRV team members are allowed to carry out this work. Also, there are detailed requirements for PPE, respiratory protection, equipment, procedures, training and disposal in our procedure. \u003c/p\u003e"},"type":"Text"}, 
