    "d28c28dd-30bf-4118-b55c-a8a1566f3fcc": {"id":"d28c28dd-30bf-4118-b55c-a8a1566f3fcc","project_id":24447,"key":81436227,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-16T20:10:39.663Z","updated_at":"2023-11-16T20:10:39.663Z","props":{"bulletColor":"#fff","enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eNo time for concerns, I have to finish the job on time.  \u003c/p\u003e"},"type":"Text"}, 
    "bc6e4fb6-f640-4d8b-9f3a-ad8d532c7eef": {"id":"bc6e4fb6-f640-4d8b-9f3a-ad8d532c7eef","project_id":24447,"key":81436221,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-16T20:10:22.703Z","updated_at":"2023-11-16T20:10:22.703Z","props":{"bulletColor":"#fff","enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eAs long as I have been trained and have the right PPE it will be okay.\u003c/p\u003e"},"type":"Text"}, 
    "4816d825-595f-4de8-9a7c-6832dcd955ee": {"id":"4816d825-595f-4de8-9a7c-6832dcd955ee","project_id":24447,"key":81436210,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-16T20:10:00.068Z","updated_at":"2023-11-16T20:10:00.068Z","props":{"bulletColor":"#fff","enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eStop work immediately and reach out to your People Leader\u003c/p\u003e"},"type":"Text"}, 
