    "9787d989-eeef-40cc-838c-459d6644e863": {"id":"9787d989-eeef-40cc-838c-459d6644e863","project_id":24447,"key":81435818,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-11-16T20:07:22.064Z","updated_at":"2023-11-16T20:07:22.064Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003ch5 data-type=\"heading-five\"\u003e\u003cp data-type=\"paragraph\"\u003eKeeping Each Other Safe.\u003c/p\u003e\u003c/h5\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eWhether you work in sales or operations. If you suspect asbestos in any property, then act as if it is asbestos. Record it, take a photo and dress in the necessary PPE.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eDuring assessments and pre-inspection take a good look into the roof cavity. Inspect and make notes the route that an installer or technician will need to take and start the risk assessment.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cul class=\"chameleon-ul\" data-type=\"bulleted-list\"\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eIs the route clear of obstruction? \u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eIf there is suspected old insulation or pipe lagging etc. does the HRV worker need to crawl through it or near it? \u003c/li\u003e\u003cli class=\"chameleon-li\" data-type=\"list-item\"\u003eIs there a lot of dust nearby?\u003c/li\u003e\u003c/ul\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eYou will have a risk assessment checklist to prompt you on what to look for and what to consider for a variety of risk factors – cavity height, electrical, structural, asbestos etc.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eYou will need to estimate how far a person will be from any suspected ACM\u003c/p\u003e"},"type":"Text"}, 
    "61ee5c6c-2211-458a-87b9-e71116e855cd": {"id":"61ee5c6c-2211-458a-87b9-e71116e855cd","project_id":24447,"key":81435808,"version":null,"meta":{"subType":"Multichoice","layout":"TwoColumns"},"children":[{"type":"Ref","id":"51065c86-b076-463d-8293-73005fa017da"},{"type":"Ref","id":"601d9669-4ca8-4173-89ef-fa501bbc151d"},{"type":"Ref","id":"c97691a7-ddcd-463d-851a-354da4301fd7"}],"deleted_at":null,"created_at":"2023-11-16T20:06:52.238Z","updated_at":"2023-11-16T20:06:52.238Z","props":{"name":"Multichoice #3","sId":23,"style":{"background":"","foreground":"","buttonBackground":"","buttonForeground":""},"textColor":"","correctOptions":"1","numberOfAttempts":1,"lockDown":1,"showCorrectAnswer":1,"useUniqueOptionFeedback":false,"score":true,"panelBackgroundOpacity":100,"panelBorderRadius":5,"panelBackground":"#0275b5","randomizeOptions":true},"type":"Interaction"}, 
