    "8022e51f-bccb-4e4e-a524-d3d721629162": {"id":"8022e51f-bccb-4e4e-a524-d3d721629162","project_id":24447,"key":75913886,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-10-12T20:41:46.659Z","updated_at":"2023-10-12T20:41:46.659Z","props":{"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eEach region has an asbestos waste disposal process for ACM and disposable PPE.\u003c/p\u003e"},"type":"Text"}, 
    "fe4d29f2-c465-4170-a034-405852207ae5": {"id":"fe4d29f2-c465-4170-a034-405852207ae5","project_id":24447,"key":75913853,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-10-12T20:41:26.945Z","updated_at":"2023-10-12T20:41:26.945Z","props":{"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eOperational teams carry out asbestos-related work, including the use of specific PPE and equipment. \u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eOnly trained and equipped workers are authorized to carry out asbestos-related work or access an area suspected of containing asbestos.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003e\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eStandards for technicians and others accessing a cavity where asbestos is suspected although their work may not involve ACM is outlined in our SOP.\u003c/p\u003e"},"type":"Text"}, 
