    "815d3de3-3292-4f71-9ad4-1e925878580a": {"id":"815d3de3-3292-4f71-9ad4-1e925878580a","project_id":24447,"key":75528770,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-10-10T21:22:25.999Z","updated_at":"2023-10-10T21:22:25.999Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eThese materials were used less frequently but still need to be recognised and risk assessed with consideration of how close an installer or technician will be during work in the cavity.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003ePhotos should be taken of all potential asbestos identified during pre-sale, pre-install and on-the-job risk assessments.\u003c/p\u003e"},"type":"Text"}, 
    "9be91c9b-c6bc-49de-80ea-167b69fef5ea": {"id":"9be91c9b-c6bc-49de-80ea-167b69fef5ea","project_id":24447,"key":75528753,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-10-10T21:22:11.480Z","updated_at":"2023-10-10T21:22:11.480Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eIf you see this type of degraded lagging then it must be recorded on the risk assessment, attach photos with an indication of how far away the installer will be during installation or servicing. This will provide guidance on a safe system of work.\u003c/p\u003e"},"type":"Text"}, 
    "ce54ee00-446f-4ee3-96f6-89571a6edeed": {"id":"ce54ee00-446f-4ee3-96f6-89571a6edeed","project_id":24447,"key":75528733,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-10-10T21:21:56.936Z","updated_at":"2023-10-10T21:21:56.936Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eSoffits on pre-2000 buildings are assumed to be ACM, unless the customer advises that they have been more recently replaced during renovations and that fits with your visual inspection.\u003c/p\u003e"},"type":"Text"}, 
    "1f0f705b-4a0c-41a7-b228-7492bf73efde": {"id":"1f0f705b-4a0c-41a7-b228-7492bf73efde","project_id":24447,"key":75528717,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-10-10T21:21:36.041Z","updated_at":"2023-10-10T21:21:36.041Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eTextured or “popcorn” ceilings found in homes built prior to 2000 may contain asbestos as it was mixed with plaster to create the desired effect. As potential friable Class A asbestos HRV does not drill into or disturb this product.\u003c/p\u003e"},"type":"Text"}, 
    "8be7abb6-2093-4a78-ac58-f12f3a5039b0": {"id":"8be7abb6-2093-4a78-ac58-f12f3a5039b0","project_id":24447,"key":75528708,"version":null,"meta":{},"children":[],"deleted_at":null,"created_at":"2023-10-10T21:21:20.054Z","updated_at":"2023-10-10T21:21:20.054Z","props":{"useBackgroundControls":true,"enableTextToSpeechBtn":true,"content":"\u003cp data-type=\"paragraph\"\u003eCorrugated cement roofing, including lap cement dust, may contain asbestos.\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eThis is a photo of Super Six roofing. HRV no longer installs new systems in pre-2000 properties with Super Six\u003c/p\u003e\u003cp data-type=\"paragraph\"\u003eroofing because of the potential extent of ACM dust and debris in the roof cavity.\u003c/p\u003e"},"type":"Text"}, 
